      {/* Heat drain to Resistor */}
      <FlowParticles 
        from={[0, 1.5, 0]} to={[0, -1.5, 0]} 
        count={drainToResCount} speed={1.5} color="#ef4444" opacity={loss_norm} curve={0.1}
