// lib/audioEngine.ts
// MEMBER 3 — Audio Sonification
// Converts RLC resonant frequency and damping into audible sound.

class AudioEngine {
  private ctx: AudioContext | null = null

  private init() {
    if (!this.ctx && typeof window !== 'undefined') {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)()
    }
  }

  /**
   * Plays a decaying sine wave tone.
   * @param frequency Resonance frequency (Hz)
   * @param decay Damping coefficient alpha (1/s)
   * @param duration Total duration (s)
   */
  public playPulse(frequency: number, decay: number, duration: number = 2) {
    this.init()
    if (!this.ctx) return

    // Resume context if suspended (browser security)
    if (this.ctx.state === 'suspended') {
      this.ctx.resume()
    }

    const osc = this.ctx.createOscillator()
    const gain = this.ctx.createGain()
    const filter = this.ctx.createBiquadFilter()

    // Map circuit parameters to audio
    // We cap frequency to comfortable human ranges [100Hz - 2000Hz]
    const audioFreq = Math.min(2000, Math.max(100, frequency))

    osc.type = 'sine'
    osc.frequency.setValueAtTime(audioFreq, this.ctx.currentTime)

    // Initial volume
    gain.gain.setValueAtTime(0.3, this.ctx.currentTime)

    // Exponential decay: V = V0 * exp(-alpha * t)
    // We map alpha directly to the gain decay ramp
    // Audio API's exponentialRamp expects a non-zero end value
    const endValue = 0.0001
    gain.gain.exponentialRampToValueAtTime(endValue, this.ctx.currentTime + duration)

    // Subtly animate frequency if underdamped (simulating subtle drift/character)
    osc.frequency.exponentialRampToValueAtTime(audioFreq * 0.99, this.ctx.currentTime + duration)

    filter.type = 'lowpass'
    filter.frequency.setValueAtTime(audioFreq * 2, this.ctx.currentTime)

    osc.connect(filter)
    filter.connect(gain)
    gain.connect(this.ctx.destination)

    osc.start()
    osc.stop(this.ctx.currentTime + duration)
  }
}

export const audioEngine = new AudioEngine()

// store/rlcStore.ts
// MEMBER 1 — Zustand State Store (Phase 2)

import { create } from 'zustand'
import { solveRLC, RLCResult } from '@/lib/physics'

interface RLCStore {
  R: number; L: number; C: number; V0: number
  result: RLCResult

  // Playback
  timeIndex: number
  isPlaying: boolean
  playbackSpeed: number

  // Noise
  noiseEnabled: boolean
  noiseLevel: number

  // Modes
  quantumMode: boolean
  oscMode: boolean
  compareMode: boolean
  storyMode: boolean

  // Actions
  setR: (v: number) => void
  setL: (v: number) => void
  setC: (v: number) => void
  setV0: (v: number) => void
  setTimeIndex: (i: number) => void
  setPlaying: (v: boolean) => void
  setPlaybackSpeed: (v: number) => void
  toggleNoise: () => void
  setNoiseLevel: (v: number) => void
  toggleQuantumMode: () => void
  toggleOscMode: () => void
  toggleCompareMode: () => void
  toggleStoryMode: () => void
  resetStore: () => void
}

const DEFAULT_R = 10
const DEFAULT_L = 0.1
const DEFAULT_C = 0.001
const DEFAULT_V0 = 10

function addNoise(signal: number[], level: number): number[] {
  const maxAmp = Math.max(...signal.map(Math.abs))
  return signal.map((v) => {
    // Basic Box-Muller for Gaussian noise
    const u1 = Math.random() + 1e-10
    const u2 = Math.random()
    const gaussian = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2)
    return v + gaussian * level * maxAmp * 0.05
  })
}

function recompute(R: number, L: number, C: number, V0: number, noiseEnabled: boolean, noiseLevel: number): RLCResult {
  const base = solveRLC(R, L, C, V0)
  if (!noiseEnabled) return base
  return {
    ...base,
    V: addNoise(base.V, noiseLevel),
  }
}

export const useRLCStore = create<RLCStore>((set, get) => ({
  R: DEFAULT_R, L: DEFAULT_L, C: DEFAULT_C, V0: DEFAULT_V0,
  result: solveRLC(DEFAULT_R, DEFAULT_L, DEFAULT_C, DEFAULT_V0),

  timeIndex: 0,
  isPlaying: false,
  playbackSpeed: 1,

  noiseEnabled: false,
  noiseLevel: 0.1,

  quantumMode: false,
  oscMode: false,
  compareMode: false,
  storyMode: false,

  setR: (R) => set((s) => ({ R, timeIndex: 0, result: recompute(R, s.L, s.C, s.V0, s.noiseEnabled, s.noiseLevel) })),
  setL: (L) => set((s) => ({ L, timeIndex: 0, result: recompute(s.R, L, s.C, s.V0, s.noiseEnabled, s.noiseLevel) })),
  setC: (C) => set((s) => ({ C, timeIndex: 0, result: recompute(s.R, s.L, C, s.V0, s.noiseEnabled, s.noiseLevel) })),
  setV0: (V0) => set((s) => ({ V0, timeIndex: 0, result: recompute(s.R, s.L, s.C, V0, s.noiseEnabled, s.noiseLevel) })),

  setTimeIndex: (timeIndex) => set({ timeIndex }),
  setPlaying: (isPlaying) => set({ isPlaying }),
  setPlaybackSpeed: (playbackSpeed) => set({ playbackSpeed }),

  toggleNoise: () => set((s) => {
    const noiseEnabled = !s.noiseEnabled
    return { noiseEnabled, timeIndex: 0, result: recompute(s.R, s.L, s.C, s.V0, noiseEnabled, s.noiseLevel) }
  }),
  setNoiseLevel: (noiseLevel) => set((s) => ({
    noiseLevel,
    result: recompute(s.R, s.L, s.C, s.V0, s.noiseEnabled, noiseLevel)
  })),

  toggleQuantumMode: () => set((s) => ({ quantumMode: !s.quantumMode })),
  toggleOscMode: () => set((s) => ({ oscMode: !s.oscMode })),
  toggleCompareMode: () => set((s) => ({ compareMode: !s.compareMode })),
  toggleStoryMode: () => set((s) => ({ storyMode: !s.storyMode })),

  resetStore: () => set({
    R: DEFAULT_R, L: DEFAULT_L, C: DEFAULT_C, V0: DEFAULT_V0,
    result: solveRLC(DEFAULT_R, DEFAULT_L, DEFAULT_C, DEFAULT_V0),
    timeIndex: 0, isPlaying: false, playbackSpeed: 1,
    noiseEnabled: false, quantumMode: false, oscMode: false,
    compareMode: false, storyMode: false
  })
}))
